211	fn run_command(result: Result<(), Box<dyn std::error::Error>>) -> ExitCode {
212	    match result {
213	        Ok(()) => ExitCode::SUCCESS,
214	        Err(e) => {
215	            error!("{e}");
216	            ExitCode::FAILURE
217	        }
218	    }
219	}
