160	/// Run a shell command. Returns stdout on success.
161	///
162	/// Logs the command at `debug!` and the process streams as follows:
163	/// - **stderr at `debug!`** on success — jj's chatter (`Moved 1 bookmarks
164	///   to …`, `Rebased N commits`, `Nothing changed.`) is hidden by default
165	///   and surfaced with `-v`. The debug formatter indents each line two
166	///   spaces so subprocess output sits visually under the caller's own
167	///   `info!` line in `-v` mode.
168	/// - **stdout at `debug!`** — callers usually consume stdout as data
169	///   (bookmark lists, commit IDs, etc.), and `info!` would flood the user
170	///   with machine-readable output they didn't ask for.
171	/// - **Failures propagate as `Err`** carrying the stderr; the caller's
172	///   error handler (`main::run_command`) surfaces it at `error!`.
173	pub fn run(cmd: &str, args: &[&str], cwd: &Path) -> Result<String, Box<dyn std::error::Error>> {
174	    let args_str = args.join(" ");
175	    debug!("$ {cmd} {args_str}");
176	    trace!("cwd: {}", cwd.display());
177	    let output = std::process::Command::new(cmd)
178	        .args(args)
179	        .current_dir(cwd)
180	        .output()
181	        .map_err(|e| format!("failed to run {cmd}: {e}"))?;
182	    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
183	    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
184	    if !stdout.is_empty() {
185	        debug!("{stdout}");
186	    }
187	    if !output.status.success() {
188	        return Err(format!("{cmd} {args_str} failed: {stderr}").into());
189	    }
190	    if !stderr.is_empty() {
191	        debug!("{stderr}");
192	    }
193	    Ok(stdout)
194	}
