307	/// Format: just the short changeID.
308	pub fn format_chid(commit: &Commit) -> String {
309	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
310	    change_hex[..change_hex.len().min(12)].to_string()
311	}
312	
313	/// Format: changeID commitID [bookmarks |] first-line (single line).
314	///
315	/// When `bookmarks` is non-empty it is inserted before the title with a `|`
316	/// separator (mirroring jj's `<chid> <hash> <bookmark> | <title>` style).
317	pub fn format_commit_short(commit: &Commit, bookmarks: &str) -> String {
318	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
319	    let change_short = &change_hex[..change_hex.len().min(12)];
320	    let commit_hex = commit.id().hex();
321	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
322	    let first_line = commit.description().lines().next().unwrap_or(""); // OK: obvious
323	    let title = if first_line.is_empty() {
324	        "(no description set)"
325	    } else {
326	        first_line
327	    };
328	    if bookmarks.is_empty() {
329	        format!("{change_short} {commit_short} {title}")
330	    } else {
331	        format!("{change_short} {commit_short} {bookmarks} | {title}")
332	    }
333	}
334	
335	/// Format: changeID commitID [bookmarks |] first-line, then remaining description lines.
336	///
337	/// Same header rules as `format_commit_short`; body lines follow unchanged.
338	pub fn format_commit_full(commit: &Commit, bookmarks: &str) -> String {
339	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
340	    let change_short = &change_hex[..change_hex.len().min(12)];
341	    let commit_hex = commit.id().hex();
342	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
343	    let desc = commit.description();
344	    if desc.is_empty() {
345	        return if bookmarks.is_empty() {
346	            format!("{change_short} {commit_short} (no description set)")
347	        } else {
348	            format!("{change_short} {commit_short} {bookmarks} | (no description set)")
349	        };
350	    }
351	    let mut lines = desc.lines();
352	    let first_line = lines.next().unwrap_or(""); // OK: obvious
353	    let mut result = if bookmarks.is_empty() {
354	        format!("{change_short} {commit_short} {first_line}")
355	    } else {
356	        format!("{change_short} {commit_short} {bookmarks} | {first_line}")
357	    };
358	    for line in lines {
359	        result.push('\n');
360	        result.push_str(line);
361	    }
362	    result
363	}
