365	/// Collect commit IDs for `..x..` (both directions) or any dot notation.
366	///
367	/// Returns `(commit_ids, anchor_index)` — the IDs in display order
368	/// (descendants closest to anchor, anchor, ancestors closest to anchor)
369	/// and the index of the anchor commit within the list.
370	///
371	/// - `desc_count`: `Some(n)` = n closest descendants, `None` = all, `Some(0)` = none
372	/// - `anc_count`: `Some(n)` = n closest ancestors, `None` = all, `Some(0)` = none
373	pub fn collect_ids(
374	    workspace: &Workspace,
375	    repo: &Arc<ReadonlyRepo>,
376	    rev: &str,
377	    desc_count: Option<usize>,
378	    anc_count: Option<usize>,
379	) -> Result<(Vec<CommitId>, usize), Box<dyn std::error::Error>> {
380	    let anchor_ids = resolve_revset(workspace, repo, rev)?;
381	    if anchor_ids.is_empty() {
382	        return Err(format!("no commit found for revision '{rev}'").into());
383	    }
384	    let anchor_id = &anchor_ids[0];
385	    let root_commit_id = repo.store().root_commit_id().clone();
386	
387	    // Descendants (closest to anchor)
388	    let mut desc_ids: Vec<CommitId> = Vec::new();
389	    if desc_count != Some(0) {
390	        let descendant_ids = resolve_revset(workspace, repo, &format!("{rev}::"))?;
391	        desc_ids = descendant_ids
392	            .into_iter()
393	            .filter(|id| *id != root_commit_id && *id != *anchor_id)
394	            .collect();
395	        if let Some(n) = desc_count {
396	            let start = desc_ids.len().saturating_sub(n);
397	            desc_ids = desc_ids[start..].to_vec();
398	        }
399	    }
400	
401	    // Ancestors (closest to anchor)
402	    let mut anc_ids: Vec<CommitId> = Vec::new();
403	    if anc_count != Some(0) {
404	        let ancestor_ids = resolve_revset(workspace, repo, &format!("::{rev}"))?;
405	        let limit = anc_count.unwrap_or(usize::MAX); // OK: no --ancestors limit → unbounded
406	        let mut count = 0;
407	        for commit_id in ancestor_ids {
408	            if commit_id == root_commit_id || commit_id == *anchor_id {
409	                continue;
410	            }
411	            anc_ids.push(commit_id);
412	            count += 1;
413	            if count >= limit {
414	                break;
415	            }
416	        }
417	    }
418	
419	    let anchor_index = desc_ids.len();
420	    let mut result = desc_ids;
421	    result.push(anchor_id.clone());
422	    result.extend(anc_ids);
423	    Ok((result, anchor_index))
424	}
