527	/// Parse and evaluate a revset string, returning commit IDs.
528	pub fn resolve_revset(
529	    workspace: &Workspace,
530	    repo: &Arc<ReadonlyRepo>,
531	    revset_str: &str,
532	) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
533	    let aliases_map = RevsetAliasesMap::new();
534	    let fileset_aliases_map = FilesetAliasesMap::new();
535	    let extensions = RevsetExtensions::default();
536	    let workspace_root = workspace.workspace_root().to_path_buf();
537	    let path_converter = RepoPathUiConverter::Fs {
538	        cwd: workspace_root.clone(),
539	        base: workspace_root,
540	    };
541	    let workspace_name = workspace.workspace_name();
542	    let workspace_ctx = RevsetWorkspaceContext {
543	        path_converter: &path_converter,
544	        workspace_name,
545	    };
546	    let context = RevsetParseContext {
547	        aliases_map: &aliases_map,
548	        local_variables: HashMap::new(),
549	        user_email: "",
550	        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
551	        default_ignored_remote: None,
552	        fileset_aliases_map: &fileset_aliases_map,
553	        use_glob_by_default: false,
554	        extensions: &extensions,
555	        workspace: Some(workspace_ctx),
556	    };
557	
558	    let mut diagnostics = RevsetDiagnostics::new();
559	    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
560	
561	    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
562	    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
563	    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
564	    let revset = resolved.evaluate(repo.as_ref())?;
565	
566	    let mut commit_ids = Vec::new();
567	    for result in revset.iter() {
568	        commit_ids.push(result?);
569	    }
570	    Ok(commit_ids)
571	}
