573	/// Scan `jj bookmark list -a <name>` output for non-tracking remote refs.
574	///
575	/// Tracked remotes appear indented (`  @origin: ...`); non-tracking remotes
576	/// appear at column 0 as `<bookmark>@<remote>: ...`. Returns the
577	/// non-tracking remote name if any is found.
578	pub fn find_non_tracking_remote(list_output: &str, bookmark: &str) -> Option<String> {
579	    let prefix = format!("{bookmark}@");
580	    for line in list_output.lines() {
581	        if line.starts_with(&prefix)
582	            && let Some(rest) = line.strip_prefix(&prefix)
583	            && let Some((remote, _)) = rest.split_once(':')
584	        {
585	            return Some(remote.to_string());
586	        }
587	    }
588	    None
589	}
