591	/// Verify all remote refs for `bookmark` in `repo` are tracked.
592	///
593	/// Returns `Err` with the exact `jj bookmark track …` remediation command if
594	/// any non-tracking remote ref is found. Used as a preflight by repo-modifying
595	/// commands (sync, push, finalize) and as a post-condition assertion by setup
596	/// commands (init, clone, test-fixture).
597	pub fn verify_tracking(repo: &Path, bookmark: &str) -> Result<(), Box<dyn std::error::Error>> {
598	    let repo_str = repo.to_string_lossy();
599	    let cwd = Path::new(".");
600	    let all = run(
601	        "jj",
602	        &["bookmark", "list", "-a", bookmark, "-R", &repo_str],
603	        cwd,
604	    )?;
605	    if let Some(remote) = find_non_tracking_remote(&all, bookmark) {
606	        return Err(format!(
607	            "bookmark '{bookmark}' has non-tracking remote '{bookmark}@{remote}' — \
608	             run `jj bookmark track {bookmark} --remote={remote} -R {repo_str}` to fix"
609	        )
610	        .into());
611	    }
612	    Ok(())
613	}
