40	    /// Value is `CODE[,BOT]`. If `BOT` is omitted, defaults to the sibling
41	    /// directory `<CODE>.claude` (file-name concat, not path join — they are
42	    /// not nested). Non-hidden contents are copied recursively; hidden
43	    /// entries (names starting with `.`) are skipped since init creates the
44	    /// repo's own hidden files. If either template has a `README.md`, its
45	    /// first line is rewritten to `# <repo-name>`.
46	    #[arg(long, value_name = "CODE[,BOT]")]
