80	use crate::common::{mkdir_p, run, write_file};
81	
82	/// Parse the `--use-template` value into `(code, bot)` template paths.
83	///
84	/// Format: `CODE[,BOT]`. If `BOT` is omitted, the default is the sibling
85	/// directory whose name is `<CODE-basename>.claude` (via
86	/// `Path::with_file_name`, so a trailing slash on `CODE` does not produce
87	/// a different result).
88	pub(crate) fn parse_use_template(
89	    s: &str,
90	) -> Result<(PathBuf, PathBuf), Box<dyn std::error::Error>> {
91	    let mut parts = s.splitn(2, ',');
92	    let code_raw = parts.next().unwrap_or(""); // OK: splitn always yields at least one element
93	    let bot_raw = parts.next();
94	    let code_trim = code_raw.trim();
95	    if code_trim.is_empty() {
96	        return Err("--use-template: code template path is empty".into());
97	    }
98	    let code = PathBuf::from(code_trim);
99	    let bot = match bot_raw.map(str::trim) {
100	        Some(b) if !b.is_empty() => PathBuf::from(b),
101	        _ => {
102	            let file_name = code.file_name().ok_or_else(|| {
103	                format!(
104	                    "--use-template: cannot derive default bot path from '{}' (no file name component)",
105	                    code.display()
106	                )
107	            })?;
108	            let new_name = format!("{}.claude", file_name.to_string_lossy());
109	            code.with_file_name(new_name)
110	        }
111	    };
112	    Ok((code, bot))
113	}
114	
115	/// Top-level non-hidden files init writes. Kept here so that if init is
116	/// ever extended to write non-hidden top-level files, the pre-flight
117	/// conflict scan flags any template that would clash. Currently empty
118	/// because init only writes hidden files (`.vc-config.toml`, `.gitignore`),
119	/// and the template copy skips hidden entries.
120	const RESERVED_TEMPLATE_ENTRIES: &[&str] = &[];
121	
122	/// Validate that both template paths exist, are directories, and contain no
123	/// top-level non-hidden entry that would collide with a file init writes.
124	pub(crate) fn validate_templates(
125	    code: &Path,
126	    bot: &Path,
127	) -> Result<(), Box<dyn std::error::Error>> {
128	    for (label, p) in [("code", code), ("bot", bot)] {
129	        if !p.exists() {
130	            return Err(format!(
131	                "--use-template: {label} template '{}' does not exist",
132	                p.display()
133	            )
134	            .into());
135	        }
136	        if !p.is_dir() {
137	            return Err(format!(
138	                "--use-template: {label} template '{}' is not a directory",
139	                p.display()
140	            )
141	            .into());
142	        }
143	        for entry in std::fs::read_dir(p)? {
144	            let entry = entry?;
145	            let name = entry.file_name();
146	            let name_str = name.to_string_lossy();
147	            if name_str.starts_with('.') {
148	                continue;
149	            }
150	            if RESERVED_TEMPLATE_ENTRIES.contains(&name_str.as_ref()) {
151	                return Err(format!(
152	                    "--use-template: {label} template '{}' contains reserved entry '{}'",
153	                    p.display(),
154	                    name_str
155	                )
156	                .into());
157	            }
158	        }
159	    }
160	    Ok(())
161	}
162	
163	/// Recursively copy non-hidden entries from `src` to `dst`. Any entry whose
164	/// file name starts with `.` is skipped. Symlinks are skipped with a debug
165	/// log — templates don't need them, and following them risks escaping the
166	/// template tree.
167	pub(crate) fn copy_template_recursive(
168	    src: &Path,
169	    dst: &Path,
170	) -> Result<(), Box<dyn std::error::Error>> {
171	    for entry in std::fs::read_dir(src)? {
172	        let entry = entry?;
173	        let name = entry.file_name();
174	        let name_str = name.to_string_lossy();
175	        if name_str.starts_with('.') {
176	            continue;
177	        }
178	        let src_path = entry.path();
179	        let dst_path = dst.join(&name);
180	        let ft = entry.file_type()?;
181	        if ft.is_symlink() {
182	            debug!("skip symlink {}", src_path.display());
183	            continue;
184	        }
185	        if ft.is_dir() {
186	            mkdir_p(&dst_path)?;
187	            copy_template_recursive(&src_path, &dst_path)?;
188	        } else if ft.is_file() {
189	            debug!("copy {} -> {}", src_path.display(), dst_path.display());
190	            std::fs::copy(&src_path, &dst_path)?;
191	        }
192	    }
193	    Ok(())
194	}
195	
196	/// Replace the first line of `<dir>/README.md` with `# <name>`. If
197	/// `README.md` is absent, this is a no-op. Trailing content after the
198	/// first newline is preserved verbatim; a file with no newline becomes
199	/// just `# <name>`.
200	pub(crate) fn rewrite_readme_first_line(
201	    dir: &Path,
202	    name: &str,
203	) -> Result<(), Box<dyn std::error::Error>> {
204	    let readme = dir.join("README.md");
205	    if !readme.exists() {
206	        return Ok(());
207	    }
208	    let content = std::fs::read_to_string(&readme)?;
209	    let rest = match content.find('\n') {
210	        Some(pos) => &content[pos..],
211	        None => "",
212	    };
213	    let new_content = format!("# {name}{rest}");
214	    std::fs::write(&readme, new_content)?;
215	    debug!("rewrote first line of {}", readme.display());
216	    Ok(())
217	}
