249	const VC_CONFIG_CODE: &str = r#"# vc-config: Vibe Coding workspace configuration
250	#
251	# workspace-path is this repo's path relative to the workspace root.
252	# Used to resolve changeID paths in git trailers (e.g. ochid: /changeID).
