282	pub fn init(args: &InitArgs) -> Result<(), Box<dyn std::error::Error>> {
283	    debug!("init: enter");
284	    let parent_dir = match &args.dir {
285	        Some(d) => d.clone(),
286	        None => std::env::current_dir()?,
287	    };
288	    let project_dir = parent_dir.join(&args.name);
289	    let session_dir = project_dir.join(".claude");
290	
291	    // Preflight checks
292	    info!("Preflight checks...");
293	
294	    // Check tools
295	    run("gh", &["auth", "status"], Path::new("."))
296	        .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
297	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
298	
299	    let owner = match &args.owner {
300	        Some(o) => o.clone(),
301	        None => gh_whoami()?,
302	    };
303	
304	    if project_dir.exists() {
305	        return Err(format!("'{}' already exists", project_dir.display()).into());
306	    }
307	
308	    let code_repo = format!("{owner}/{}", args.name);
309	    let session_repo = format!("{owner}/{}.claude", args.name);
310	
311	    if gh_repo_exists(&owner, &args.name)? {
312	        return Err(format!("GitHub repo '{code_repo}' already exists").into());
313	    }
314	    if gh_repo_exists(&owner, &format!("{}.claude", args.name))? {
315	        return Err(format!("GitHub repo '{session_repo}' already exists").into());
316	    }
317	
318	    let templates = match &args.use_template {
319	        Some(s) => {
320	            let (code_t, bot_t) = parse_use_template(s)?;
321	            validate_templates(&code_t, &bot_t)?;
322	            Some((code_t, bot_t))
323	        }
324	        None => None,
325	    };
326	
327	    let visibility = if args.private {
328	        "--private"
329	    } else {
330	        "--public"
331	    };
332	
333	    if args.dry_run {
334	        info!("Dry run — would execute:");
335	        info!("  1. Create directories: {}", project_dir.display());
336	        info!("  2. git init + jj git init --colocate on both repos");
337	        info!("  3. Write .vc-config.toml and .gitignore to both");
338	        match &templates {
339	            Some((c, b)) => {
340	                info!(
341	                    "  4. Copy templates (non-hidden) into both repos + rewrite README.md first line"
342	                );
343	                info!("       code: {}", c.display());
344	                info!("       bot:  {}", b.display());
345	            }
346	            None => info!("  4. (skipped — no --use-template)"),
347	        }
348	        info!("  5. jj commit both with placeholder ochids");
349	        info!("  6. Get both chids, jj describe both with correct ochids");
350	        info!("  7. Remove jj from both (git clean -xdf)");
351	        info!("  8. gh repo create {session_repo} {visibility}, push");
352	        info!("  9. gh repo create {code_repo} {visibility}, push");
353	        info!("  10. jj git init --colocate on both repos");
354	        info!("  11. Create Claude Code symlink");
355	        return Ok(());
356	    }
357	
358	    // Step 1: Create directories
359	    info!("Step 1: Creating project directories...");
360	    mkdir_p(&project_dir)?;
361	    mkdir_p(&session_dir)?;
362	
363	    // Step 2: git init + jj init on both repos
364	    info!("Step 2: Initializing repos...");
365	    run("git", &["init"], &project_dir)?;
366	    run("jj", &["git", "init", "--colocate"], &project_dir)?;
367	    run("git", &["init"], &session_dir)?;
368	    run("jj", &["git", "init", "--colocate"], &session_dir)?;
369	
370	    // Step 3: Write config files
371	    info!("Step 3: Writing config files...");
372	    write_file(&project_dir.join(".vc-config.toml"), VC_CONFIG_CODE)?;
373	    write_file(&project_dir.join(".gitignore"), GITIGNORE_CODE)?;
374	    write_file(&session_dir.join(".vc-config.toml"), VC_CONFIG_SESSION)?;
375	    write_file(&session_dir.join(".gitignore"), GITIGNORE_SESSION)?;
376	
377	    // Step 4: Copy templates (if --use-template)
378	    if let Some((code_t, bot_t)) = &templates {
379	        info!("Step 4: Copying templates...");
380	        info!("  code: {} -> {}", code_t.display(), project_dir.display());
381	        copy_template_recursive(code_t, &project_dir)?;
382	        rewrite_readme_first_line(&project_dir, &args.name)?;
383	        info!("  bot:  {} -> {}", bot_t.display(), session_dir.display());
384	        copy_template_recursive(bot_t, &session_dir)?;
385	        let session_name = format!("{}.claude", args.name);
386	        rewrite_readme_first_line(&session_dir, &session_name)?;
387	    }
388	
389	    // Step 5: jj commit both with placeholder ochids
390	    info!("Step 5: Committing both repos with placeholder ochids...");
391	    run(
392	        "jj",
393	        &["commit", "-m", "Initial commit\n\nochid: /none"],
394	        &project_dir,
395	    )?;
396	    run(
397	        "jj",
398	        &["commit", "-m", "Initial commit\n\nochid: /none"],
399	        &session_dir,
400	    )?;
401	
402	    // Step 6: Get both chids, then describe both with correct ochids
403	    info!("Step 6: Setting ochid cross-references...");
404	    let code_chid = jj_chid("@-", &project_dir)?;
405	    let session_chid = jj_chid("@-", &session_dir)?;
406	
407	    let code_desc = format!("Initial commit\n\nochid: /.claude/{session_chid}");
408	    let session_desc = format!("Initial commit\n\nochid: /{code_chid}");
409	    run("jj", &["describe", "@-", "-m", &code_desc], &project_dir)?;
410	    run("jj", &["describe", "@-", "-m", &session_desc], &session_dir)?;
411	
412	    {
413	        let hash = run("git", &["rev-parse", "HEAD"], &project_dir)?;
414	        debug!("code repo: chid={code_chid} hash={hash}");
415	        let hash = run("git", &["rev-parse", "HEAD"], &session_dir)?;
416	        debug!(".claude:   chid={session_chid} hash={hash}");
417	    }
418	
419	    // Step 7: Set bookmarks (creates git branches), then remove jj
420	    // Bookmarks must be set before removing .jj/ so git has a 'main' branch to push
421	    info!("Step 7: Setting bookmarks and removing jj...");
422	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
423	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
424	    // Clean .claude first, then code repo with --exclude to preserve .claude/
425	    run("git", &["clean", "-xdf"], &session_dir)?;
426	    run(
427	        "git",
428	        &["clean", "-xdf", "--exclude", ".claude"],
429	        &project_dir,
430	    )?;
431	    // After removing .jj/, git HEAD is detached — reattach to main
432	    run("git", &["checkout", "main"], &session_dir)?;
433	    run("git", &["checkout", "main"], &project_dir)?;
434	
435	    // Step 8: Create .claude GitHub repo and push
436	    let session_url = format!("git@github.com:{session_repo}.git");
437	    info!("Step 8: Creating GitHub repo {session_repo}...");
438	    run(
439	        "gh",
440	        &["repo", "create", &session_repo, visibility],
441	        &project_dir,
442	    )?;
443	    run(
444	        "git",
445	        &["remote", "add", "origin", &session_url],
446	        &session_dir,
447	    )?;
448	    run_retry(
449	        "git",
450	        &["push", "-u", "origin", "main"],
451	        &session_dir,
452	        args.push_retries,
453	        args.push_retry_delay,
454	    )?;
455	
456	    // Step 9: Create code GitHub repo and push
457	    let code_url = format!("git@github.com:{code_repo}.git");
458	    info!("Step 9: Creating GitHub repo {code_repo}...");
459	    run(
460	        "gh",
461	        &["repo", "create", &code_repo, visibility],
462	        &project_dir,
463	    )?;
464	    run("git", &["remote", "add", "origin", &code_url], &project_dir)?;
465	    run_retry(
466	        "git",
467	        &["push", "-u", "origin", "main"],
468	        &project_dir,
469	        args.push_retries,
470	        args.push_retry_delay,
471	    )?;
472	
473	    // Step 10: Re-initialize jj on both repos
474	    info!("Step 10: Re-initializing jj on both repos...");
475	    run(
476	        "jj",
477	        &["--quiet", "git", "init", "--colocate"],
478	        &project_dir,
479	    )?;
480	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
481	    run(
482	        "jj",
483	        &["bookmark", "track", "main", "--remote=origin"],
484	        &project_dir,
485	    )?;
486	    crate::common::verify_tracking(&project_dir, "main")?;
487	    let code_chid_final = jj_chid("@-", &project_dir)?;
488	
489	    run(
490	        "jj",
491	        &["--quiet", "git", "init", "--colocate"],
492	        &session_dir,
493	    )?;
494	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
495	    run(
496	        "jj",
497	        &["bookmark", "track", "main", "--remote=origin"],
498	        &session_dir,
499	    )?;
500	    crate::common::verify_tracking(&session_dir, "main")?;
501	    let session_chid_final = jj_chid("@-", &session_dir)?;
502	
503	    // Step 11: Create Claude Code symlink
504	    info!("Step 11: Creating Claude Code symlink...");
505	    let symlink_dir = {
506	        let home =
507	            std::env::var("HOME").map_err(|_| "HOME environment variable not set".to_string())?;
508	        PathBuf::from(home).join(".claude").join("projects")
509	    };
510	
511	    let sl = symlink::SymLink::new(&project_dir, Path::new(".claude"), &symlink_dir)?;
512	    sl.create(false)?;
513	
514	    info!("");
515	    info!("Done! Project created at {}", project_dir.display());
516	    info!("  Code repo:    {code_repo}  (chid={code_chid_final})");
517	    info!("  Session repo: {session_repo}  (chid={session_chid_final})");
518	    info!(
519	        "  Symlink:      {} -> {}",
520	        sl.symlink_path.display(),
521	        sl.abs_target.display()
522	    );
523	
524	    debug!("init: exit");
525	    Ok(())
526	}
