//! Scope of operation — which repo(s) a command should act on.
//!
//! Shared across commands that may run in single-repo, dual-repo, or
//! plain-old-repo (POR) workspaces. See
//! `notes/chores-06.md > Generalize --scope across commands (0.40.0)`
//! for the full design, including the default-resolution and
//! ambiguity rules.

use clap::ValueEnum;

/// Which repo(s) a command should operate on.
#[derive(Copy, Clone, Debug, PartialEq, Eq, ValueEnum)]
pub enum Scope {
    /// Operate only on the app repo (the workspace's `path = "/"` side).
    App,
    /// Operate only on the counterpart repo (via `other-repo` in
    /// `.vc-config.toml`).
    Other,
    /// Operate on both repos together (dual-repo workspace only).
    Both,
}

