/// Single-repo init — creates one jj/git repo, one GitHub repo, no
/// `.claude` session, no `ochid:` trailer. Used when the caller
/// passes `--scope=app` to signal "plain-old-repo with vc-x1
/// tooling, no companion."
fn init_app(args: &InitArgs) -> Result<(), Box<dyn std::error::Error>> {
    debug!("init_app: enter");
    let parent_dir = match &args.dir {
        Some(d) => d.clone(),
        None => std::env::current_dir()?,
    };
    let project_dir = parent_dir.join(&args.name);

    info!("Preflight checks...");

    run("gh", &["auth", "status"], Path::new("."))
        .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;

    let owner = match &args.owner {
        Some(o) => o.clone(),
        None => gh_whoami()?,
    };

    if project_dir.exists() {
        return Err(format!("'{}' already exists", project_dir.display()).into());
    }

    let code_repo = format!("{owner}/{}", args.name);
    if gh_repo_exists(&owner, &args.name)? {
        return Err(format!("GitHub repo '{code_repo}' already exists").into());
    }

    // In --scope=app, --use-template takes a single CODE path. A
    // comma indicates dual-repo intent (CODE,BOT) — fatal per the
    // ambiguity rule in `notes/chores-06.md > Generalize --scope ...`.
    let template = match &args.use_template {
        Some(s) => {
            if s.contains(',') {
                return Err(format!(
                    "--scope=app takes a single template path; got '{s}' (remove the `,BOT` half or use --scope=both)"
                )
                .into());
            }
            let trimmed = s.trim();
            if trimmed.is_empty() {
                return Err("--use-template: code template path is empty".into());
            }
            let code_t = PathBuf::from(trimmed);
            if !code_t.exists() {
                return Err(format!(
                    "--use-template: code template '{}' does not exist",
                    code_t.display()
                )
                .into());
            }
            if !code_t.is_dir() {
                return Err(format!(
                    "--use-template: code template '{}' is not a directory",
                    code_t.display()
                )
                .into());
            }
            Some(code_t)
        }
        None => None,
    };

    let visibility = if args.private {
        "--private"
    } else {
        "--public"
    };

    if args.dry_run {
        info!("Dry run — would execute:");
        info!("  1. Create directory: {}", project_dir.display());
        info!("  2. git init + jj git init --colocate");
        info!("  3. Write .vc-config.toml (app-only) and .gitignore");
        match &template {
            Some(c) => {
                info!("  4. Copy template (non-hidden) + rewrite README.md first line");
                info!("       code: {}", c.display());
            }
            None => info!("  4. (skipped — no --use-template)"),
        }
        info!("  5. jj commit initial commit (no ochid trailer)");
        info!("  6. Set bookmark, remove jj, re-init jj");
        info!("  7. gh repo create {code_repo} {visibility}, push");
        return Ok(());
    }

    // Step 1
    info!("Step 1: Creating project directory...");
    mkdir_p(&project_dir)?;

    // Step 2
    info!("Step 2: Initializing repo...");
    run("git", &["init"], &project_dir)?;
    run("jj", &["git", "init", "--colocate"], &project_dir)?;

    // Step 3
    info!("Step 3: Writing config files...");
    write_file(&project_dir.join(".vc-config.toml"), VC_CONFIG_APP_ONLY)?;
    write_file(&project_dir.join(".gitignore"), GITIGNORE_APP_ONLY)?;

    // Step 4
    if let Some(code_t) = &template {
        info!("Step 4: Copying template...");
        info!("  code: {} -> {}", code_t.display(), project_dir.display());
        copy_template_recursive(code_t, &project_dir)?;
        rewrite_readme_first_line(&project_dir, &args.name)?;
    }

    // Step 5: single repo, no ochid cross-reference needed.
    info!("Step 5: Committing initial commit...");
    run("jj", &["commit", "-m", "Initial commit"], &project_dir)?;

    // Step 6: set bookmark, strip jj, re-init jj so the git remote
    // and jj bookmark tracking both land cleanly.
    info!("Step 6: Setting bookmark and resetting jj...");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
    run("git", &["clean", "-xdf"], &project_dir)?;
    run("git", &["checkout", "main"], &project_dir)?;

    // Step 7: create GitHub repo and push.
    let code_url = format!("git@github.com:{code_repo}.git");
    info!("Step 7: Creating GitHub repo {code_repo}...");
    run(
        "gh",
        &["repo", "create", &code_repo, visibility],
        &project_dir,
    )?;
    run("git", &["remote", "add", "origin", &code_url], &project_dir)?;
    run_retry(
        "git",
        &["push", "-u", "origin", "main"],
        &project_dir,
        args.push_retries,
        args.push_retry_delay,
    )?;

    // Step 8: re-initialize jj with remote tracking.
    info!("Step 8: Re-initializing jj with remote tracking...");
    run(
        "jj",
        &["--quiet", "git", "init", "--colocate"],
        &project_dir,
    )?;
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
    run(
        "jj",
        &["bookmark", "track", "main", "--remote=origin"],
        &project_dir,
    )?;
    crate::common::verify_tracking(&project_dir, "main")?;
    let code_chid_final = jj_chid("@-", &project_dir)?;

    info!("");
    info!("Done! Project created at {}", project_dir.display());
    info!("  Repo: {code_repo}  (chid={code_chid_final})");

    debug!("init_app: exit");
    Ok(())
}

