#[test]
fn config_content_app_only() {
    // App-only config: has path, but deliberately no other-repo —
    // its absence is how callers detect the single-repo state.
    assert!(VC_CONFIG_APP_ONLY.contains("path = \"/\""));
    assert!(!VC_CONFIG_APP_ONLY.contains("other-repo"));
}

#[test]
fn gitignore_app_only_excludes_no_claude() {
    // App-only gitignore drops /.claude (no session dir) but keeps
    // the other standard entries.
    assert!(!GITIGNORE_APP_ONLY.contains(".claude"));
    assert!(GITIGNORE_APP_ONLY.contains("/.git"));
    assert!(GITIGNORE_APP_ONLY.contains("/.jj"));
    assert!(GITIGNORE_APP_ONLY.contains("/.vc-x1"));
}

#[test]
fn scope_defaults_to_none() {
    let args = parse(&["vc-x1", "init", "my-project"]);
    assert!(args.scope.is_none());
}

#[test]
fn scope_parses_app() {
    let args = parse(&["vc-x1", "init", "my-project", "--scope", "app"]);
    assert_eq!(args.scope, Some(Scope::App));
}

#[test]
fn scope_parses_other() {
    let args = parse(&["vc-x1", "init", "my-project", "--scope", "other"]);
    assert_eq!(args.scope, Some(Scope::Other));
