    // Bookmarks must be set before removing .jj/ so git has a 'main' branch to push
    info!("Step 7: Setting bookmarks and removing jj...");
    debug!("place code-side main bookmark at the initial commit");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
    debug!("place session-side main bookmark at the initial commit");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
    debug!("strip jj state from session side before its git push");
    run("git", &["clean", "-xdf"], &session_dir)?;
    debug!("strip jj state from code side, preserving nested .claude/");
    run(
        "git",
        &["clean", "-xdf", "--exclude", ".claude"],
        &project_dir,
    )?;
    debug!("re-attach session HEAD to main after clean");
    run("git", &["checkout", "main"], &session_dir)?;
    debug!("re-attach code HEAD to main after clean");
    run("git", &["checkout", "main"], &project_dir)?;

    // Step 8: Session-side remote + push.
    if using_gh {
        info!("Step 8: Creating GitHub repo {session_repo}...");
        debug!("create session-side remote on GitHub");
        run(
            "gh",
            &["repo", "create", &session_repo, visibility],
            &project_dir,
        )?;
    } else {
        info!("Step 8: Using supplied session remote {session_url}");
    }
    debug!("point session-side git at its remote");
    run(
        "git",
        &["remote", "add", "origin", &session_url],
        &session_dir,
    )?;
    debug!("publish session-side initial commit; retry since a fresh gh repo may need a moment");
    run_retry(
        "git",
        &["push", "-u", "origin", "main"],
        &session_dir,
        args.push_retries,
        args.push_retry_delay,
    )?;

    // Step 9: Code-side remote + push.
    if using_gh {
        info!("Step 9: Creating GitHub repo {code_repo}...");
        debug!("create code-side remote on GitHub");
        run(
            "gh",
            &["repo", "create", &code_repo, visibility],
            &project_dir,
        )?;
    } else {
        info!("Step 9: Using supplied code remote {code_url}");
    }
    debug!("point code-side git at its remote");
    run("git", &["remote", "add", "origin", &code_url], &project_dir)?;
    debug!("publish code-side initial commit; retry since a fresh gh repo may need a moment");
    run_retry(
        "git",
        &["push", "-u", "origin", "main"],
        &project_dir,
        args.push_retries,
        args.push_retry_delay,
    )?;

    // Step 10: Re-initialize jj on both repos
    info!("Step 10: Re-initializing jj on both repos...");
    debug!("re-colocate jj atop the now-remote-linked code repo");
    run(
        "jj",
        &["--quiet", "git", "init", "--colocate"],
        &project_dir,
    )?;
    debug!("restore code-side main bookmark after re-init");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
    debug!("enable jj tracking of code-side main against origin");
    run(
        "jj",
        &["bookmark", "track", "main", "--remote=origin"],
        &project_dir,
    )?;
    crate::common::verify_tracking(&project_dir, "main")?;
    let code_chid_final = jj_chid("@-", &project_dir)?;

    debug!("re-colocate jj atop the now-remote-linked session repo");
    run(
        "jj",
        &["--quiet", "git", "init", "--colocate"],
        &session_dir,
    )?;
    debug!("restore session-side main bookmark after re-init");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
    debug!("enable jj tracking of session-side main against origin");
    run(
        "jj",
        &["bookmark", "track", "main", "--remote=origin"],
        &session_dir,
    )?;
    crate::common::verify_tracking(&session_dir, "main")?;
    let session_chid_final = jj_chid("@-", &session_dir)?;

    // Step 11: Create Claude Code symlink
    info!("Step 11: Creating Claude Code symlink...");
    let symlink_dir = {
        let home =
            std::env::var("HOME").map_err(|_| "HOME environment variable not set".to_string())?;
        PathBuf::from(home).join(".claude").join("projects")
    };

    let sl = symlink::SymLink::new(&project_dir, Path::new(".claude"), &symlink_dir)?;
    sl.create(false)?;

    info!("");
    info!("Done! Project created at {}", project_dir.display());
    info!("  Code repo:    {code_url}  (chid={code_chid_final})");
    info!("  Session repo: {session_url}  (chid={session_chid_final})");
    info!(
        "  Symlink:      {} -> {}",
        sl.symlink_path.display(),
        sl.abs_target.display()
    );

    debug!("init: exit");
    Ok(())
}

