/// Resolve the on-disk project root from either `--repo-local` or the
/// positional `NAME` + optional `--dir`. Exactly one pathway must
/// supply the placement — NAME and `--repo-local` are mutually
/// exclusive (ambiguity rule), and `--dir` only composes with NAME
/// (it would be redundant under `--repo-local`).
fn resolve_project_dir(args: &InitArgs) -> Result<PathBuf, Box<dyn std::error::Error>> {
    match (&args.name, &args.repo_local) {
        (Some(_), Some(_)) => Err(
            "NAME and --repo-local are mutually exclusive (both specify on-disk placement)".into(),
        ),
        (None, None) => Err("NAME or --repo-local is required".into()),
        (Some(name), None) => {
            let parent_dir = match &args.dir {
                Some(d) => d.clone(),
                None => std::env::current_dir()?,
            };
            Ok(parent_dir.join(name))
        }
        (None, Some(spec)) => {
            if args.dir.is_some() {
                return Err(
                    "--dir and --repo-local are mutually exclusive (both specify placement)".into(),
                );
            }
            if spec.contains(',') {
                return Err(format!(
                    "--repo-local takes a single path; got '{spec}' (session side is always <PATH>/.claude)"
                )
                .into());
            }
            normalize_local_path(spec)
        }
    }
}

/// Resolve remote URLs from `--repo-remote` if present, normalizing
/// both halves. Returns `None` when the flag is absent — the caller
/// will derive URLs via `gh repo create`.
fn resolve_remotes(
    args: &InitArgs,
) -> Result<Option<(String, String)>, Box<dyn std::error::Error>> {
    match &args.repo_remote {
        None => Ok(None),
        Some(spec) => {
            if args.owner.is_some() {
                return Err("--repo-remote and --owner are mutually exclusive (no GitHub derivation happens when remotes are explicit)".into());
            }
            if args.private {
                return Err("--repo-remote and --private are mutually exclusive (--private only affects `gh repo create`)".into());
            }
            let (code_raw, bot_raw) = split_code_bot(spec, "--repo-remote")?;
            Ok(Some((
                normalize_remote(&code_raw)?,
                normalize_remote(&bot_raw)?,
            )))
        }
    }
}

pub fn init(args: &InitArgs) -> Result<(), Box<dyn std::error::Error>> {
    debug!("init: enter");

    // Resolve placement + remote URLs from the flag combinations.
    let project_dir = resolve_project_dir(args)?;
    let session_dir = project_dir.join(".claude");
    let explicit_remotes = resolve_remotes(args)?;

    // Project name for README rewriting + (when needed) GitHub repo
    // name derivation. Comes from basename of project_dir whether
    // that was from NAME or --repo-local.
    let name = project_dir
        .file_name()
        .ok_or_else(|| {
            format!(
                "cannot derive project name from '{}'",
                project_dir.display()
            )
        })?
        .to_string_lossy()
        .to_string();
    let session_name = format!("{name}.claude");

    // Preflight checks
    info!("Preflight checks...");

    debug!("verify jj is installed");
    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;

    let using_gh = explicit_remotes.is_none();
    if using_gh {
        debug!("verify gh CLI is installed + authenticated");
        run("gh", &["auth", "status"], Path::new("."))
            .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
    }

    // GitHub owner is only meaningful when deriving URLs via gh.
    let owner = if using_gh {
        match &args.owner {
            Some(o) => o.clone(),
            None => gh_whoami()?,
        }
    } else {
        String::new() // OK: unused when explicit_remotes is Some
    };

    if project_dir.exists() {
        return Err(format!("'{}' already exists", project_dir.display()).into());
    }

    // GitHub existence precheck only matters when we're about to
    // create those repos. With --repo-remote, we assume the caller
    // already has the target set up (or intends to receive the push).
    let (code_repo, session_repo, code_url, session_url) = match &explicit_remotes {
        None => {
            let code_repo = format!("{owner}/{name}");
            let session_repo = format!("{owner}/{session_name}");
            if gh_repo_exists(&owner, &name)? {
                return Err(format!("GitHub repo '{code_repo}' already exists").into());
            }
            if gh_repo_exists(&owner, &session_name)? {
                return Err(format!("GitHub repo '{session_repo}' already exists").into());
            }
            let code_url = format!("git@github.com:{code_repo}.git");
            let session_url = format!("git@github.com:{session_repo}.git");
            (code_repo, session_repo, code_url, session_url)
        }
        Some((c, s)) => (
            // Repo-name slots aren't used in log output when remotes
            // are explicit — still populate for consistency.
            String::new(),
            String::new(),
            c.clone(),
            s.clone(),
        ),
    };

    let templates = match &args.use_template {
        Some(s) => {
            let (code_t, bot_t) = parse_use_template(s)?;
            validate_templates(&code_t, &bot_t)?;
            Some((code_t, bot_t))
        }
        None => None,
    };

    let visibility = if args.private {
        "--private"
    } else {
        "--public"
    };

    if args.dry_run {
        info!("Dry run — would execute:");
        info!("  1. Create directories: {}", project_dir.display());
        info!("  2. git init + jj git init --colocate on both repos");
        info!("  3. Write .vc-config.toml and .gitignore to both");
        match &templates {
            Some((c, b)) => {
                info!(
                    "  4. Copy templates (non-hidden) into both repos + rewrite README.md first line"
                );
                info!("       code: {}", c.display());
                info!("       bot:  {}", b.display());
            }
            None => info!("  4. (skipped — no --use-template)"),
        }
        info!("  5. jj commit both with placeholder ochids");
        info!("  6. Get both chids, jj describe both with correct ochids");
        info!("  7. Remove jj from both (git clean -xdf)");
        if using_gh {
            info!("  8. gh repo create {session_repo} {visibility}, push to {session_url}");
            info!("  9. gh repo create {code_repo} {visibility}, push to {code_url}");
        } else {
            info!("  8. skip gh repo create; push to {session_url}");
            info!("  9. skip gh repo create; push to {code_url}");
        }
        info!("  10. jj git init --colocate on both repos");
        info!("  11. Create Claude Code symlink");
        return Ok(());
    }

    // Step 1: Create directories
    info!("Step 1: Creating project directories...");
    mkdir_p(&project_dir)?;
    mkdir_p(&session_dir)?;

    // Step 2: git init + jj init on both repos
    info!("Step 2: Initializing repos...");
    debug!("seed project_dir with an empty git repo");
    run("git", &["init"], &project_dir)?;
    debug!("colocate jj atop the git repo so jj + git share .git state");
    run("jj", &["git", "init", "--colocate"], &project_dir)?;
    debug!("seed session_dir with an empty git repo");
    run("git", &["init"], &session_dir)?;
    debug!("colocate jj atop the session git repo");
    run("jj", &["git", "init", "--colocate"], &session_dir)?;

    // Step 3: Write config files
    info!("Step 3: Writing config files...");
    write_file(&project_dir.join(".vc-config.toml"), VC_CONFIG_CODE)?;
    write_file(&project_dir.join(".gitignore"), GITIGNORE_CODE)?;
    write_file(&session_dir.join(".vc-config.toml"), VC_CONFIG_SESSION)?;
    write_file(&session_dir.join(".gitignore"), GITIGNORE_SESSION)?;

    // Step 4: Copy templates (if --use-template)
    if let Some((code_t, bot_t)) = &templates {
        info!("Step 4: Copying templates...");
        info!("  code: {} -> {}", code_t.display(), project_dir.display());
        copy_template_recursive(code_t, &project_dir)?;
        rewrite_readme_first_line(&project_dir, &name)?;
        info!("  bot:  {} -> {}", bot_t.display(), session_dir.display());
        copy_template_recursive(bot_t, &session_dir)?;
        rewrite_readme_first_line(&session_dir, &session_name)?;
    }

    // Step 5: jj commit both with placeholder ochids
    info!("Step 5: Committing both repos with placeholder ochids...");
    debug!("code side: first commit with placeholder ochid (rewritten in step 6 once session chid known)");
    run(
        "jj",
        &["commit", "-m", "Initial commit\n\nochid: /none"],
        &project_dir,
    )?;
    debug!("session side: first commit with placeholder ochid (rewritten in step 6)");
    run(
        "jj",
        &["commit", "-m", "Initial commit\n\nochid: /none"],
        &session_dir,
    )?;

    // Step 6: Get both chids, then describe both with correct ochids
    info!("Step 6: Setting ochid cross-references...");
    let code_chid = jj_chid("@-", &project_dir)?;
    let session_chid = jj_chid("@-", &session_dir)?;

    let code_desc = format!("Initial commit\n\nochid: /.claude/{session_chid}");
    let session_desc = format!("Initial commit\n\nochid: /{code_chid}");
    debug!("code side: rewrite initial commit's ochid to point at session chid");
    run("jj", &["describe", "@-", "-m", &code_desc], &project_dir)?;
    debug!("session side: rewrite initial commit's ochid to point at code chid");
    run("jj", &["describe", "@-", "-m", &session_desc], &session_dir)?;

    {
        debug!("sanity: surface both post-describe git hashes for the debug log");
        let hash = run("git", &["rev-parse", "HEAD"], &project_dir)?;
        debug!("code repo: chid={code_chid} hash={hash}");
        let hash = run("git", &["rev-parse", "HEAD"], &session_dir)?;
        debug!(".claude:   chid={session_chid} hash={hash}");
    }

    // Step 7: Set bookmarks (creates git branches), then remove jj
    // Bookmarks must be set before removing .jj/ so git has a 'main' branch to push
    info!("Step 7: Setting bookmarks and removing jj...");
    debug!("place code-side main bookmark at the initial commit");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
    debug!("place session-side main bookmark at the initial commit");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
    debug!("strip jj state from session side before its git push");
    run("git", &["clean", "-xdf"], &session_dir)?;
    debug!("strip jj state from code side, preserving nested .claude/");
    run(
        "git",
        &["clean", "-xdf", "--exclude", ".claude"],
        &project_dir,
    )?;
    debug!("re-attach session HEAD to main after clean");
    run("git", &["checkout", "main"], &session_dir)?;
    debug!("re-attach code HEAD to main after clean");
    run("git", &["checkout", "main"], &project_dir)?;

    // Step 8: Session-side remote + push.
    if using_gh {
        info!("Step 8: Creating GitHub repo {session_repo}...");
        debug!("create session-side remote on GitHub");
        run(
            "gh",
            &["repo", "create", &session_repo, visibility],
            &project_dir,
        )?;
    } else {
        info!("Step 8: Using supplied session remote {session_url}");
    }
    debug!("point session-side git at its remote");
    run(
        "git",
        &["remote", "add", "origin", &session_url],
        &session_dir,
    )?;
    debug!("publish session-side initial commit; retry since a fresh gh repo may need a moment");
    run_retry(
        "git",
        &["push", "-u", "origin", "main"],
        &session_dir,
        args.push_retries,
        args.push_retry_delay,
    )?;

    // Step 9: Code-side remote + push.
    if using_gh {
        info!("Step 9: Creating GitHub repo {code_repo}...");
        debug!("create code-side remote on GitHub");
        run(
            "gh",
            &["repo", "create", &code_repo, visibility],
            &project_dir,
        )?;
    } else {
        info!("Step 9: Using supplied code remote {code_url}");
    }
    debug!("point code-side git at its remote");
    run("git", &["remote", "add", "origin", &code_url], &project_dir)?;
    debug!("publish code-side initial commit; retry since a fresh gh repo may need a moment");
    run_retry(
        "git",
        &["push", "-u", "origin", "main"],
        &project_dir,
        args.push_retries,
        args.push_retry_delay,
    )?;

    // Step 10: Re-initialize jj on both repos
    info!("Step 10: Re-initializing jj on both repos...");
    debug!("re-colocate jj atop the now-remote-linked code repo");
    run(
        "jj",
        &["--quiet", "git", "init", "--colocate"],
        &project_dir,
    )?;
    debug!("restore code-side main bookmark after re-init");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
    debug!("enable jj tracking of code-side main against origin");
    run(
        "jj",
        &["bookmark", "track", "main", "--remote=origin"],
        &project_dir,
    )?;
    crate::common::verify_tracking(&project_dir, "main")?;
    let code_chid_final = jj_chid("@-", &project_dir)?;

    debug!("re-colocate jj atop the now-remote-linked session repo");
    run(
        "jj",
        &["--quiet", "git", "init", "--colocate"],
        &session_dir,
    )?;
    debug!("restore session-side main bookmark after re-init");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
    debug!("enable jj tracking of session-side main against origin");
    run(
        "jj",
        &["bookmark", "track", "main", "--remote=origin"],
        &session_dir,
    )?;
    crate::common::verify_tracking(&session_dir, "main")?;
    let session_chid_final = jj_chid("@-", &session_dir)?;

    // Step 11: Create Claude Code symlink
    info!("Step 11: Creating Claude Code symlink...");
    let symlink_dir = {
        let home =
            std::env::var("HOME").map_err(|_| "HOME environment variable not set".to_string())?;
        PathBuf::from(home).join(".claude").join("projects")
    };

    let sl = symlink::SymLink::new(&project_dir, Path::new(".claude"), &symlink_dir)?;
    sl.create(false)?;

    info!("");
    info!("Done! Project created at {}", project_dir.display());
    info!("  Code repo:    {code_url}  (chid={code_chid_final})");
    info!("  Session repo: {session_url}  (chid={session_chid_final})");
    info!(
        "  Symlink:      {} -> {}",
        sl.symlink_path.display(),
        sl.abs_target.display()
    );

    debug!("init: exit");
    Ok(())
}

