#[derive(Args, Debug)]
pub struct InitArgs {
    /// Project name (directory and GitHub repo name).
    ///
    /// Optional when `--repo-remote` is given — the name is derived
    /// from the URL's last path segment (trailing `.git` stripped).
    /// Required with `--repo-local` and with the default
    /// GitHub-creation mode. If both NAME and `--repo-remote` are
    /// given and the derived names disagree, that's a fatal error.
    #[arg(value_name = "NAME")]
    pub name: Option<String>,

    /// GitHub user or organization. Only meaningful in the default
    /// GitHub-creation mode; passing it with `--repo-local` or
    /// `--repo-remote` is a fatal error (neither mode uses it).
    #[arg(long)]
    pub owner: Option<String>,

    /// Parent directory to create the project under [default: cwd].
    /// Ignored (fatal error) when `--repo-local` is given — that
    /// flag already supplies the parent.
    #[arg(long)]
    pub dir: Option<PathBuf>,

    /// Create private GitHub repos (default: public). Only
    /// meaningful in the default GitHub-creation mode; passing it
    /// with `--repo-local` or `--repo-remote` is a fatal error.
    #[arg(long)]
    pub private: bool,

    /// Dry run — show what would be done without executing
    #[arg(long)]
    pub dry_run: bool,

    /// Max push retries after repo creation [default: 5]
    #[arg(long, default_value_t = 5)]
    pub push_retries: u32,

    /// Seconds between push retries [default: 3]
    #[arg(long, default_value_t = 3)]
    pub push_retry_delay: u64,

    /// Seed both repos from template directories.
    ///
    /// Value is `CODE[,BOT]`. If `BOT` is omitted, defaults to the sibling
    /// directory `<CODE>.claude` (file-name concat, not path join — they are
    /// not nested). Non-hidden contents are copied recursively; hidden
    /// entries (names starting with `.`) are skipped since init creates the
    /// repo's own hidden files. If either template has a `README.md`, its
    /// first line is rewritten to `# <repo-name>`.
    #[arg(long, value_name = "CODE[,BOT]")]
    pub use_template: Option<String>,

    /// Fixture mode — create a fully self-contained local workspace.
    ///
    /// Value is a single parent directory. init creates:
    /// `<PARENT>/<NAME>/` (project), `<PARENT>/<NAME>/.claude/`
    /// (session), `<PARENT>/remote-code.git` (bare, code origin),
    /// `<PARENT>/remote-claude.git` (bare, session origin). No
    /// `gh`, no network. May use `~/…` or `$VAR` / `${VAR}`;
    /// relative paths resolve against cwd. Mutually exclusive with
    /// `--repo-remote`, `--dir`, `--owner`, `--private`.
    #[arg(long, value_name = "PARENT")]
    pub repo_local: Option<String>,

    /// Override the `origin` URL stem. Value is a single URL (or
    /// path); the session-side URL is derived by inserting
    /// `.claude` before a trailing `.git`, or appending `.claude`
    /// if no `.git` suffix. For GitHub URLs the repo is still
    /// created via `gh repo create` (same code path as the
    /// default); for non-GitHub URLs init pushes to the URL
    /// without any create step — the caller is responsible for
    /// the remote existing. May use `~/…` or `$VAR` / `${VAR}`
    /// in path-shaped values. Mutually exclusive with
    /// `--repo-local`, `--owner`, `--private`.
    #[arg(long, value_name = "URL")]
    pub repo_remote: Option<String>,
}

